#include<stdio.h>
#include<math.h>
int main()
{
	int x1,y1,x2,y2,n,bal,mal;
	scanf("%d%d%d%d%d",&n,&x1,&y1,&x2,&y2);
	if (x1==x2 && y1==y2) printf("0");
	else if ((x1==0 && x2==0)|| (x1==n&&x2==n)) printf("%d",abs(y1-y2));
	else if ((y1==0 && y2==0)|| (y1==n&&y2==n)) printf("%d",abs(x1-x2));
	else if (x1==0 && y2==n)
	{
		printf("%d",(n-y1)+x2);
	}
	else if (x1==n && y2==0)
	{
		printf("%d",(n-x2)+y1);
	}
	else if (x2==0 && y1==n)
	{
		printf("%d",(n-y2)+x1);
	}
	else if (x2==n && y1==0)
	{
		printf("%d",(n-x1)+y2);
	}
	else 
	{
		bal=x1+x2+y1+y2;
		mal=4*n-bal;
		if (bal<=mal) printf("%d",bal);
		else printf("%d",mal);
	}
}

