use std::cmp::min;
use std::io::{stdin};

fn get_pos(n: u16, x: u16, y: u16) -> Option<u16> {
    if (x > n) || (y > n) {
        return None;
    }

    if y == 0 {
        if x == 0 {
            return Some(0);
        } else {
            return Some(4 * n - x);
        }
    } else if y == n {
        return Some(n + x);
    } else if x == 0 {
        return Some(y);
    } else if x == n {
        return Some(3 * n - y);
    } else {
        return None;
    }
}

fn get_distance(n: u16, x1: u16, y1: u16, x2: u16, y2: u16) -> Option<u16> {
    let pos1: u16 = get_pos(n, x1, y1)?;
    let pos2: u16 = get_pos(n, x2, y2)?;

    let distance_naive: u16;
    if pos1 > pos2 {
        distance_naive = pos1 - pos2;
    } else {
        distance_naive = pos2 - pos1;
    }

    return Some(min(distance_naive, 4 * n - distance_naive));
}

#[cfg(test)]
mod tests {
    use super::get_distance;

    #[test]
    fn test1() {
        assert_eq!(get_distance(2, 0, 0, 1, 0), Some(1));
    }

    #[test]
    fn test2() {
        assert_eq!(get_distance(2, 0, 1, 2, 1), Some(4));
    }

    #[test]
    fn test3() {
        assert_eq!(get_distance(100, 0, 0, 100, 100), Some(200));
    }
}

fn main() {
    let stdin = stdin();
    let mut input_line: String = String::new();
    stdin.read_line(&mut input_line).unwrap();
    let input_vec: Vec<u16> = input_line
        .trim()
        .split_whitespace()
        .map(|s| s.parse().unwrap())
        .collect();

    let n: u16 = input_vec[0];
    let x1: u16 = input_vec[1];
    let y1: u16 = input_vec[2];
    let x2: u16 = input_vec[3];
    let y2: u16 = input_vec[4];

    let distance: u16 = get_distance(n, x1, y1, x2, y2).unwrap();

    println!("{}", distance);
}
